import{_ as t,o as a,c as i,ag as o}from"./chunks/framework.YaIgwL5o.js";const g=JSON.parse('{"title":"Images","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/images.md","filePath":"tutorials/images.md"}'),n={name:"tutorials/images.md"};function r(l,e,s,d,p,c){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="images" tabindex="-1">Images <a class="header-anchor" href="#images" aria-label="Permalink to &quot;Images&quot;">​</a></h1><p>This tutorial covers inserting images and the interactive features: click-to-expand and popup text.</p><h2 id="inserting-an-image" tabindex="-1">Inserting an image <a class="header-anchor" href="#inserting-an-image" aria-label="Permalink to &quot;Inserting an image&quot;">​</a></h2><p><strong>From a URL:</strong></p><ol><li>Click the <strong>Image</strong> button in the toolbar.</li><li>Paste the image URL in the prompt and click OK.</li></ol><p><strong>By uploading:</strong></p><ol><li>Click the small upload arrow next to the Image button.</li><li>Select a file from your computer. It&#39;s uploaded to the server and inserted on the slide.</li></ol><h2 id="adjusting-an-image" tabindex="-1">Adjusting an image <a class="header-anchor" href="#adjusting-an-image" aria-label="Permalink to &quot;Adjusting an image&quot;">​</a></h2><p>Select an image to see its properties in the right panel:</p><ul><li><strong>Object Fit</strong> — <code>contain</code> (letterbox), <code>cover</code> (fill and crop), <code>fill</code> (stretch), <code>none</code> (native size)</li><li><strong>Brightness / Contrast / Grayscale</strong> — filter sliders</li><li><strong>Round Corners</strong> — adjustable border radius</li><li><strong>Crop</strong> — double-click the image to enter crop mode; drag the handles to crop</li></ul><h2 id="click-to-expand" tabindex="-1">Click to expand <a class="header-anchor" href="#click-to-expand" aria-label="Permalink to &quot;Click to expand&quot;">​</a></h2><p>This feature lets the audience click an image during a presentation to see it at full viewport size.</p><ol><li>Select the image element.</li><li>In the right panel, check <strong>Click to expand in present mode</strong>.</li><li>In present mode, hovering the image shows a subtle indigo outline. Clicking it opens a full-screen lightbox.</li><li>Click outside the image or press <code>Escape</code> to close.</li></ol><h3 id="example-output" tabindex="-1">Example output <a class="header-anchor" href="#example-output" aria-label="Permalink to &quot;Example output&quot;">​</a></h3><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/expand-image.html" style="width:100%;height:260px;border:none;"></iframe></div><h2 id="popup-text" tabindex="-1">Popup text <a class="header-anchor" href="#popup-text" aria-label="Permalink to &quot;Popup text&quot;">​</a></h2><p>Show a text tooltip when an image is clicked during presentation.</p><ol><li>Select the image element.</li><li>In the right panel, find <strong>Pop-up text (present mode)</strong> and enter your caption.</li><li>Choose the <strong>Position</strong> (Below, Centered, or Side) and <strong>Font size</strong>.</li><li>In present mode, clicking the image shows the text box. Click away or press <code>Escape</code> to dismiss.</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can enable <strong>both</strong> click-to-expand and popup text on the same image. When clicked, the image expands to full viewport and the popup text appears beside the expanded image.</p></div><h3 id="example-output-1" tabindex="-1">Example output <a class="header-anchor" href="#example-output-1" aria-label="Permalink to &quot;Example output&quot;">​</a></h3><div style="border:1px solid #333;border-radius:8px;overflow:hidden;margin:16px 0;"><iframe src="/revealjs_gui/demos/popup-image.html" style="width:100%;height:260px;border:none;"></iframe></div>',21)])])}const m=t(n,[["render",r]]);export{g as __pageData,m as default};
